var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......드디어 여기까지 오신 것 같군.","JPN":"……ようやく戻ってきたか。","ENG":"So they've made it.","TWN":"……看來他們終於到這裡來了啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"부사령관님......","JPN":"副司令官様……","ENG":"Deputy Commander...","TWN":"副司令官……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......괜찮네.","JPN":"……いいんだ。","ENG":"I'm fine.","TWN":"……不要緊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"개인적인 감정 때문에 대의를 그르칠 생각은 없으니까 말이야.","JPN":"個人的な感情のために、大儀を誤るつもりはないからな。","ENG":"I won't let my personal feelings ruin our cause.","TWN":"我不會因為個人感情而不守大義的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그보다 다친 곳은 없나, 비숍?","JPN":"それより、ケガはないのか？　ビショップ。","ENG":"Are you hurt anywhere, Bishop?","TWN":"話說回來，妳沒有受傷吧，大主教？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......상태 양호.","JPN":"……良好な状態。","ENG":"I'm mission-capable.","TWN":"……狀態良好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"테라사이드 시스템 통제에 문제는 없다.","JPN":"テラサイドシステムの統制には問題ない。","ENG":"System Terraside is also under complete control.","TWN":"要控制特拉賽德系統沒有問題。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"걱정했었는데 좋은 소식이로군.","JPN":"心配したが、それなら良かった。","ENG":"That's good news.","TWN":"我還挺擔心的呢，這真是個好消息。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"얼터너티브 실험체...... 아니, 서윤은 어떻게 됐지?","JPN":"オルタナティブ実験体……いや、アオイ・シズカはどうなった？","ENG":"What happened to the Alternative test subject—I mean, Seo Yoon?","TWN":"可替代試驗體……不，徐芸怎麼樣了？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"말씀하신 대로 배신하기 전, 미스틸테인 원본을 지급했습니다.","JPN":"ご指示どおり、裏切られる前にミスティルテインの原本を渡しました。","ENG":"As you said, she was supplied with the Misteltein, the original one, before she betrayed us.","TWN":"按照您的吩咐，我在她叛變前把原版米斯特丁給了她。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......본인은 아마 모조품이라고 알고 있겠지만요.","JPN":"……本人は模造品だと思ってるでしょうが。","ENG":"She seems to think that it's a replica.","TWN":"……不過她本人應該知道那是仿造品。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"좋아. 이걸로 만일의 사태에 대한 대비도 끝났군.","JPN":"よし、これで万一への備えも済んだな。","ENG":"Good. Then our contingency plan is complete.","TWN":"很好，這樣我們也做好發生萬一的準備了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......그럼 자네와도 이제 마지막이군.","JPN":"……これで君ともお別れだな。","ENG":"So, I guess this is the last time I'll ever see you.","TWN":"……那麼現在，和妳也是最後一次見面了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......부사령관님.","JPN":"……副司令官様。","ENG":"Deputy Commander...","TWN":"……副司令官。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네의 헌신이 없었다면 난 아무것도 해낼 수 없었을 거야.","JPN":"君の献身がなければ、私は何も成し得なかっただろう。","ENG":"I couldn't have achieved anything without your tireless efforts.","TWN":"如果沒有妳的獻身，我大概什麼都做不到吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그동안 고마웠네.","JPN":"礼を言う。","ENG":"You have my thanks.","TWN":"一直以來非常謝謝妳。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그리고...... 마지막까지 무운을 비네.","JPN":"それから……武運長久を祈る。","ENG":"And... Good luck, until the end.","TWN":"那麼……祝妳武運昌隆。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"부사령관님도...... 무운을 빕니다.","JPN":"副司令官様にも……ご武運をお祈りします。","ENG":"Good luck to you too, Deputy Commander.","TWN":"副司令官也是……祝您武運昌隆。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 지상에서 전투 중인 자칭 리플레이서 신디케이트 소속 테러리스트들에게 전한다.</color>","JPN":"<color=#ffd34c>現在、地上で戦闘を展開している自称リプレイサー・シンジケート所属のテロリストに伝える。</color>","ENG":"<color=#ffd34c>This is a warning to all the terrorists of the Replacer Syndicate, now engaged in ground combat against our forces.</color>","TWN":"<color=#ffd34c>傳達給現在在地上戰鬥，自稱是屬於克隆集團的恐怖分子們。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금 즉시 전투행위를 멈추고 모든 무장을 해제하라.</color>","JPN":"<color=#ffd34c>ただちに戦闘行為を止め、すべての武装を解除せよ。</color>","ENG":"<color=#ffd34c>Stop resisting and surrender your weapons immediately.</color>","TWN":"<color=#ffd34c>請立刻停止戰鬥行為，解除所有武裝。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>반복한다. 즉시 전투행위를 멈추고 모든 무장을 해제하라.</color>","JPN":"<color=#ffd34c>繰り返す。ただちに戦闘行為を止め、すべての武装を解除せよ。</color>","ENG":"<color=#ffd34c>I repeat. Stop resisting and surrender your weapons immediately.</color>","TWN":"<color=#ffd34c>重複一次。請立刻停止戰鬥行為，解除所有武裝。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 명령을 거부할 경우, 이후 발생할 모든 책임은 당신들에게 있음을 엄중히 경고한다.","JPN":"この要求を拒否した場合、今後発生するすべての責任は、あなた方にあることを厳重に警告する。","ENG":"You will be solely responsible for the deaths and injuries that may occur if you fail to heed this warning.","TWN":"嚴正警告，如果有不服從該命令的場合，此後發生的一切責任全部由你們承擔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......어이, 카일!","JPN":"……おい、カイル！","ENG":"Hey, Kyle!","TWN":"……等一下，凱爾！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이거 봤어? 이 여왕님께서 4종 침식체 급의 위험인물이라는데?","JPN":"これ、見たか？　この女王様が第4種侵食体級の危険人物だそうだ。","ENG":"Did you see this? It says Queen is as dangerous as a Category 4 C.O.","TWN":"你看了這個嗎？這個女皇大人是第4侵蝕體級的危險人物耶？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 보고서 쓴 정보부 놈들, 4종 침식체가 뭔지 구경은 해 보고 쓴 건지 모르겠네.","JPN":"この報告書をまとめた情報局の奴ら、第4種侵食体なんて見たことないんじゃないか？","ENG":"I wonder if any of those punks in Intelligence have ever seen a Category 4 C.O. in person.","TWN":"還真不知道寫出這份報告書的情報部傢伙，有沒有見過第4級侵蝕體咧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그렇게 생각하지 않아?","JPN":"そう思わないか？","ENG":"Don't you agree?","TWN":"你不這麼覺得嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......해당 보고서는 관리국 연합 사령부 정보실에서 작성한 공식 문건입니다.","JPN":"……その報告書は管理局連合の情報室で作成された公式文書です。","ENG":"The report is an official document submitted by the Administration Coalition Command Intelligence Office.","TWN":"……這份報告是管理局聯合司令部情報室做成的官方文件。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아군의 공식 정보채널을 의심하는 언동은 삼가해 주십시오, 대령님.","JPN":"味方の公式情報を疑うような言動は控えてください、大佐。","ENG":"I suggest that you refrain from making remarks that could be interpreted as an insult to our official channel of information.","TWN":"請克制你懷疑我們官方情報管道的行為，上校。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......아, 그래.","JPN":"……あ、そう。","ENG":"Yeah, yeah.","TWN":"……啊，好啦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여전히 재미없는 대답이네.","JPN":"相変わらず堅いな。","ENG":"You're boring as ever.","TWN":"還是這麼無趣呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그보다 사령관님, 적 지상병력으로부터 특별한 반응은 없습니다.","JPN":"それより司令官、敵の地上兵力から特段の反応はありません。","ENG":"Anyway, there's no response from enemy ground forces, Commander.","TWN":"話說回來，司令官，敵人的地上兵力沒什麼回應。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"한번 더 경고할까요?","JPN":"改めて警告しましょうか？","ENG":"Should I warn them again?","TWN":"要再警告一次嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......아니, 이번엔 내가 직접 하도록 하지.","JPN":"……いや、今度は私から直接警告しよう。","ENG":"No, I'll do it myself this time.","TWN":"……不了，這次我親自來。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"여기는 관리국 연합함대 작전 사령부,","JPN":"こちら、管理局連合艦隊の作戦司令部、","ENG":"This is TASKFORCE 1,","TWN":"這裡是管理局聯合艦隊作戰司令部，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"TASKFORCE 1.","JPN":"TASKFORCE 1。","ENG":"of the Administration Coalition Fleet operations command.","TWN":"TASKFORCE 1。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"기함 <color=#ffd34c>USSA 뉴 엔터프라이즈</color> 및 델타 세븐 겸임 사령관,","JPN":"旗艦<color=#ffd34c>USSAニューエンタープライズ</color>およびデルタセブン兼任司令官、","ENG":"I'm Lieutenant General Maria Antonov, commander of the flagship <color=#ffd34c>USSA New Enterprise</color>","TWN":"我是司令艦 <color=#ffd34c>USSA新企業號</color>和第七三角洲部隊的兼任司令官……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마리아 안토노프 중장이다.","JPN":"マリア・アントノフ中将だ。","ENG":"as well as the Delta Seven.","TWN":"瑪麗亞．安東諾夫中將。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이것은 최종 경고다.","JPN":"これは最終警告だ。","ENG":"This is our final warning.","TWN":"這是最後的警告。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금 즉시 모든 저항을 멈추고 항복하라.","JPN":"ただちにすべての抵抗をやめて降参せよ。","ENG":"Stop resisting and surrender immediately.","TWN":"立刻停止所有的抵抗，向我們投降。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지상 병력, 일부 반응을 보이기 시작했습니다.","JPN":"地上兵力の一部で反応があります。","ENG":"Some of the enemies seem flustered.","TWN":"地上的部隊一部分開始有反應了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이대로 더 압박한다면......","JPN":"このまま、さらに圧迫すれば……","ENG":"If we keep pressuring them, we could...","TWN":"再這樣繼續施壓的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......잠깐! 마리아 아줌마!","JPN":"……待って！　おばさん！","ENG":"Hang on! Maria!","TWN":"……等等！瑪麗亞大嬸！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뉴 오하이오로부터 통신이 들어오고 있어!","JPN":"ニューオハイオから通信が入ってる！","ENG":"We're receiving a transmission from the New Ohio!","TWN":"有新俄亥俄那邊的通信進來了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨! 중장님께 그게 무슨 말투입니까?!","JPN":"シルビアさん！　中将に対して、なんて口の利き方を！","ENG":"Sylvia! Watch your tone when you're talking to Lieutenant General!","TWN":"希爾維亞小姐！妳是怎麼和中將說話的！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......괜찮아, 카일.","JPN":"……大丈夫だ、カイル。","ENG":"It's okay, Kyle.","TWN":"……沒關係，凱爾。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그보다 중앙 스크린에 통신을 연결해 주겠니? 실비아.","JPN":"それより、メインスクリーンに通信先を繋いでくれるか？　シルビア。","ENG":"Put it up on the main screen, Sylvia.","TWN":"可以幫我把通信連接到中央的大螢幕上嗎？希爾維亞。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......알겠어.","JPN":"……了解。","ENG":"Copy.","TWN":"……好的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......오랜만이군요.","JPN":"……しばらくですね。","ENG":"It's been a while.","TWN":"……好久不見了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"여전히 건강하신 것 같아 기쁩니다.","JPN":"相変わらずお元気そうで何よりです。","ENG":"Glad to see you're as strong as ever,","TWN":"很高興看到您還是這麼健康的樣子。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"사령관님.","JPN":"司令官。","ENG":"Commander.","TWN":"司令官大人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"보고를 듣고도 믿기지가 않았는데...... 정말 살아 있었군.","JPN":"報告を聞いても信じられなかったが……本当に生きていたのか。","ENG":"I couldn't believe what was written in the report... So you were really alive...","TWN":"就算聽到了報告，但我還是無法相信……沒想到你真的還活著。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉.","JPN":"ドミニーク。","ENG":"Dominic.","TWN":"多明尼克。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만...... 아쉽게도 자네의 무사귀환을 반가워 할 상황이 아니라 유감이군.","JPN":"残念ながら……君の生還を喜んでる場合ではないがね。","ENG":"But... I regret that I can't welcome your safe return at all.","TWN":"不過……我很遺憾，現在這個狀況，讓我無法對你平安歸來感到高興。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 알던 자네는 이런 무모한 일을 벌일 사람이 아니었는데......","JPN":"私の知る限り、君はこんな無謀なことをしでかす人間ではなかったが……","ENG":"You weren't the type of person who would do something this reckless.","TWN":"我認識的你，是不會做這種魯莽行為的人……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대체 사라졌던 그 몇 년간 자네에게 무슨 일이 있었던 거지?","JPN":"行方不明になっていた数年間、いったい君に何があったのだ？","ENG":"What happened to you during those years you spent in hiding?","TWN":"你消失的那幾年到底發生了什麼事情？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"저도 사령관님께 제가 보고 겪은 모든 걸 설명해드리고 싶지만......","JPN":"私も司令官に自分が経験したことすべてを説明したいのですが……","ENG":"I wish I could explain everything I saw and experienced,","TWN":"我也想對司令官解釋我經歷過的事情……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"지금은 들어도 이해하실 수 없을 겁니다. 다만......","JPN":"今は話しても理解していただけないでしょう。ただ……","ENG":"but I'm afraid you won't be able to take in any of it, just yet. But...","TWN":"但是您現在就算聽說了，也不會理解的吧。只是……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다만......?","JPN":"ただ……？","ENG":"But?","TWN":"只是……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"저의 모든 행동은 사령관님과......","JPN":"私がやっていること全ては、司令官や……","ENG":"I just want to you know that everything I'm doing,","TWN":"我的所有行動，都是為了司令官……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"인류 전체를 위한 일이라는 것을 알아주시기 바랄 뿐입니다.","JPN":"全人類のためであるというのを、ご理解頂けることを願うばかりです。","ENG":"I'm doing for you, and for all mankind.","TWN":"和全體人類而做，只希望您能記住這一點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 무슨 말인지 도무지 알아들을 수가 없군.","JPN":"悪いが、まったくもって理解に苦しむな。","ENG":"I'm sorry, but I really don't understand what you're saying.","TWN":"很抱歉，我完全不明白你的意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금이라도 투항하게. 최대한 선처를 부탁해 보겠네.","JPN":"今からでも投降したまえ。できる限り、手厚くもてなそう。","ENG":"I suggest that you surrender yourself this instant. I'll make sure they don't treat you too harshly.","TWN":"現在就投降吧，我會為你請求最大限度的寬待處分。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"죄송합니다만...... 그건 불가능하겠군요.","JPN":"申し訳ありませんが……それはできません。","ENG":"I'm sorry, but that's something I can't do.","TWN":"很抱歉……這是不可能的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이해해주시길 바랍니다만...... 그게 어려우시다면......","JPN":"ご理解頂きたかったのですが……それが難しいなら……","ENG":"I really hoped you could understand, but if you can't, and you want to stop me...","TWN":"我非常希望您能理解……但如果這樣是有困難的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"힘으로 멈추셔야 할 겁니다.","JPN":"武力をもって止めるほかありません。","ENG":"I'm afraid you'll have to do it with force.","TWN":"我們就必須用武力來解決了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......협상은 결렬이군.","JPN":"……交渉決裂だな。","ENG":"The deal's off then.","TWN":"……交涉決裂了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"짧은 재회였지만 반가웠네, 도미닉.","JPN":"短い間だったが、会えて良かった、ドミニーク。","ENG":"It was short, but it was nice to see you again, Dominic.","TWN":"雖然是場短暫的再會，但我還是很高興見到你，多明尼克。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"재회의 선물로...... 편안한 최후를 선사해주지.","JPN":"再会の土産として……安らかな最期を贈ってやろう。","ENG":"And as a gift for our reunion, I'll grant you a peaceful death.","TWN":"作為再會的禮物……就送給你一個安祥的臨終吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내 입장상, 반역자에게 줄 수 있는 선물은 그것뿐이니까.","JPN":"私の立場上、反逆者に贈れるものはそれだけだからな。","ENG":"That's the only thing I can give to a traitor as the commander.","TWN":"以我的立場，能給背叛者的就只有這樣的禮物而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……なるほど。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그럼 무운을 빕니다, 사령관님.","JPN":"では、ご武運を祈ります、司令官。","ENG":"Godspeed, Commander.","TWN":"那麼祝您武運昌隆，司令官。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......자네도.","JPN":"……君もな。","ENG":"Godspeed to you, too.","TWN":"……你也是。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>적 함선으로부터 고출력 에너지 반응!</color>","JPN":"<color=#ffd34c>敵の艦船から高出力のエネルギー反応あり！</color>","ENG":"<color=#ffd34c>Massive energy response from enemy ship!</color>","TWN":"<color=#ffd34c>從敵方艦船偵測到高輸出的能量反應！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지난 번 관리국 연함 함대를 격침시켰던 불멸체 코어 에너지 시그니처와 동일합니다!</color>","JPN":"<color=#ffd34c>以前、管理局の連合艦隊を撃沈させた不滅体コアエネルギーのシグネチャーと一致します！</color>","ENG":"<color=#ffd34c>Its signature is identical with the power that was triggered by the Immortal System Core, one that sank the Administration Coalition Fleet ships!</color>","TWN":"<color=#ffd34c>和上次擊沉管理局聯合艦隊的不滅者核心能源標誌一樣！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"기관실! 블랙홀 드라이브 시동!","JPN":"機関室！　ブラックホールドライブ始動！","ENG":"Engine Room! Launch the black hole drive!","TWN":"機關室！啟動黑洞引擎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 기관실! 마이크로 블랙홀 회전 개시!</color>","JPN":"<color=#ffd34c>こちらは機関室！　マイクロブラックホールの回転開始！</color>","ENG":"<color=#ffd34c>Engine Room here! Initiating micro black hole revolution!</color>","TWN":"<color=#ffd34c>這裡是機關室！微型黑洞迴轉開始！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>블랙홀 표면 자전 속도 임계 도달! 광속의 97.8%!</color>","JPN":"<color=#ffd34c>ブラックホール表面の自転速度が臨界に到達！　光速の97.8％！</color>","ENG":"<color=#ffd34c>The surface rotation speed of the black hole has reached the critical point, currently at 97.8% of lightspeed!</color>","TWN":"<color=#ffd34c>達到黑洞表面迴轉速度臨界點！光速的97.8%！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전투정보실! 주포 사격준비!","JPN":"戦闘情報室！　主砲発射準備！","ENG":"Combat Intel, ready the cannons.","TWN":"戰鬥情報室！準備主炮射擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 전투정보실! 회전축 조준 정렬! 블랙홀 드라이브에 에너지라인 접속!</color>","JPN":"<color=#ffd34c>こちら戦闘情報室！　回転軸の照準を整列！　ブラックホールドライブにエネルギーラインを接続！</color>","ENG":"<color=#ffd34c>Combat Intel here! Aligning cannon rotation axis! Energy line connected to the black hole drive!</color>","TWN":"<color=#ffd34c>這裡是戰鬥情報室！旋轉軸照準排列！連接黑洞引擎能量線！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>블랙홀에 질량 공급 개시! 강착원반 형성!</color>","JPN":"<color=#ffd34c>ブラックホールに質量供給を開始！　固定円盤の形成よし！</color>","ENG":"<color=#ffd34c>Applying mass to the black hole! Accretion disk has been created!</color>","TWN":"<color=#ffd34c>開始向黑洞供給質量！形成著陸圓盤！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님! 발사 준비 완료입니다!","JPN":"司令官！　発射準備完了です！","ENG":"Commander, we're ready to go!","TWN":"司令官！發射準備完畢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......좋아.","JPN":"……了解。","ENG":"Good.","TWN":"……好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"주포, 감마 레이 버스터.","JPN":"主砲、ガンマ・レイ・バスター。","ENG":"Gamma Ray Burster,","TWN":"主炮，伽馬射線破壞者。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"발사!","JPN":"発射！","ENG":"fire!","TWN":"發射！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전투정보실! 사격 결과 보고하라!","JPN":"戦闘情報室！　結果を報告せよ！","ENG":"Combat Intel, do you confirm the hit?","TWN":"戰鬥情報室！報告射擊結果！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 전투정보실! 감마 레이 버스터, 뉴 오하이오에 명중!</color>","JPN":"<color=#ffd34c>こちら戦闘情報室！　ガンマ・レイ・バスター、ニューオハイオに命中！</color>","ENG":"<color=#ffd34c>Combat Intel here! The Gamma Ray Burster shot was a clear hit!</color>","TWN":"<color=#ffd34c>這裡是戰鬥情報室！伽馬射線破壞者命中新俄亥俄！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>뉴 오하이오 동력반응 상실! 항해 불능 확인!!</color>","JPN":"<color=#ffd34c>ニューオハイオの動力反応、消失！　航海不能状態を確認！！</color>","ENG":"<color=#ffd34c>New Ohio has lost all of its motive force! The ship's no longer functional!</color>","TWN":"<color=#ffd34c>新俄亥俄喪失動力反應！確認無法航行！！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 불멸체 코어의 에너지 방출을 찢어버리고 일격에 뉴 오하이오를 대파시키다니......","JPN":"あの不滅体コアのエネルギー放出を封じ込めて、一撃でニューオハイオを大破させるとは……","ENG":"That thing ripped off the energy field of the Immortal System Core and crippled the New Ohio with a single shot...","TWN":"竟然摧毀了不滅者核心的能源排放，一擊毀掉了新俄亥俄……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이게...... 블랙홀 드라이브의 힘......","JPN":"これが……ブラックホールドライブの力……","ENG":"This is the power of the black hole drive?","TWN":"這就是……黑洞引擎的力量……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"강해...... 관리국 놈들...... 이런 걸 숨기고 있었다고?","JPN":"強い……管理局の奴ら、こんなのを隠し持ってたわけ？","ENG":"It's almost shocking... How could the Administration have kept this hidden the whole time?","TWN":"太強了……管理局那些傢伙……竟然一直藏著這種東西嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 기관실! 블랙홀 드라이브 과열! 마이크로 블랙홀을 강제 증발시킵니다!</color>","JPN":"<color=#ffd34c>こちら機関室！　ブラックホールドライブが過熱状態！　マイクロブラックホールを強制消滅させています！</color>","ENG":"<color=#ffd34c>Engine Room here! Black hole drive is overheating! Evaporating the micro black hole by force!</color>","TWN":"<color=#ffd34c>這裡是機關室！黑洞引擎過熱！強制蒸發微型黑洞！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현시간부로 일반 이터니움 드라이브로 주 동력계 전환!</color>","JPN":"<color=#ffd34c>現在時刻付で、メイン動力計を一般のエタニウムドライブへ転換！</color>","ENG":"<color=#ffd34c>As of now, we're navigating on the regular Eternium Drive!</color>","TWN":"<color=#ffd34c>從現時點，切換成一般永恆之金引擎動力系統 ！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......대단하군요.","JPN":"……これはすごい。","ENG":"This is amazing.","TWN":"……真厲害呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"덕분에 엔터프라이즈의 요구 출력을 만족시킬 수 있는 엔진을 장착할 수 있긴 했지만......","JPN":"おかげさまで、エンタープライズの要求スペックを満たすエンジンは装着できましたが……","ENG":"It's a good thing that we were able to equip Enterprise with the engine with the power output it deserves,","TWN":"多虧了這個，企業號搭載了可以滿足動力需求的引擎……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"관리국은 어떻게 이런 시기에 딱 맞춰서 블랙홀 드라이브를 개발한 걸까요?","JPN":"管理局はどうやってこんな丁度のタイミングで、ブラックホールドライブを開発できたんですかね？","ENG":"but could it really be a coincidence that the Administration's development of the black hole drive finished just in time?","TWN":"但是管理局是怎麼會這麼剛好，在這個時候開發出黑洞引擎呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"거기다가 굳이 참관선 명목으로 하필이면 아직 채 수리되지도 않은 <color=#ffd34c>저 함선</color>을 딸려 보낸 건 더더욱 의심스럽습니다.","JPN":"それに、よりによってまだ修理も終わっていない<color=#ffd34c>あの艦船</color>を\\nわざわざ付き添わせるなんて、ますます疑わしいです。","ENG":"Besides, they sent <color=#ffd34c>that ship</color> as an observer when it hasn't fully been repaired yet. I can't help but feel but suspicious.","TWN":"何況還是刻意以參觀船的名義，順便附在尚未修理好的<color=#ffd34c>那艘艦船</color>一起送過來，這更是讓人起疑。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......너무 고민하지 말게, 카일.","JPN":"……あまり深追いしなくていい、カイル。","ENG":"Don’t fret over it too much, Kyle.","TWN":"……別太擔心了，凱爾。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"중요한 건 그 도움으로 우리가 적기함 뉴 오하이오를 간단히 격침시켰다는 거야.","JPN":"重要なのは、そのおかげで我々が敵の旗艦、ニューオハイオを易々と撃沈できたことだからな。","ENG":"What's important is that we sank the enemy flagship without much effort, thanks to their help.","TWN":"重要的是在它的幫助下，我們才能輕易地擊沉新俄亥俄。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 궁금한 게 없진 않지만...... 적을 앞에 두고 우리가 할 일은 하나지.","JPN":"私も気がかりなことはあるが……敵を目前にしている我々のやるべきことは、これに尽きるだろう。","ENG":"I have my own questions as well, but this isn't the time to raise answers. There are enemies in front of us.","TWN":"雖然我也不是不好奇……但在敵人面前，我們能做的就只有一件事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크. 준비됐나?","JPN":"ジェイク、準備はいいか？","ENG":"Jake, are you ready?","TWN":"傑克，準備好了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네! 중장님!","JPN":"はい、中将！","ENG":"Yes, Lieutenant General.","TWN":"是的！中將大人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"전략특수전 사령부 제 7델타분견대! 전원 지상 강하 준비 완료됐습니다!","JPN":"戦略特殊戦司令部、第7デルタ分遣隊！　全員、地上降下の準備完了です！","ENG":"The 7th Delta Detachment of the Strategic Special Operations Command, all set and ready to jump out.","TWN":"戰略特種作戰司令部第七三角洲分遣隊！全員地面降落準備完畢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아. 나도 현장지휘는 오랜만이로군.","JPN":"よし、現場の指揮は私も久しぶりだな。","ENG":"Good. It's been a while since I last went out on the field.","TWN":"很好。我也很久沒在現場指揮了呢。"},"stage":{"bg":"MAINSTREAM_5502011","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전방은 자네에게 맡기면 되겠지? 잘 부탁하네.","JPN":"前方は君に任せていいな？　よろしく頼むぞ。","ENG":"I'll count on you to take care of the front.","TWN":"前方可以交給你吧？拜託你了喔。"},"stage":{"bg":"MAINSTREAM_5502011","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"맡겨만 주십시오, 중장님!","JPN":"お任せを！　中将！","ENG":"Rest assured, Lieutenant General.","TWN":"交給我吧，中將大人。"},"stage":{"bg":"MAINSTREAM_5502011","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"절대 실망시켜드리지 않겠습니다.","JPN":"決して失望はさせません。","ENG":"I won't disappoint you.","TWN":"我絕對不會讓您失望的。"},"stage":{"bg":"MAINSTREAM_5502011","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};